    UiTemplateService.prototype.getIntersections = function (obj1, obj2) {
        var left1 = obj1.x;
        var right1 = obj1.x + obj1.width;
        var top1 = obj1.y;
        var bottom1 = obj1.y + obj1.height;
        var left2 = obj2.x;
        var right2 = obj2.x + obj2.width;
        var top2 = obj2.y;
        var bottom2 = obj2.y + obj2.height;
        if (left1 >= right2 || top1 >= bottom2 ||
            right1 <= left2 || bottom1 <= top2) {
            return false;
        }
        else {
            return [right2 - left1, bottom2 - top1, right1 - left2, bottom1 - top2];
        }
    };
    UiTemplateService.prototype.calculateFontSize = function (apiData) {
        var xVals = [];
        var yVals = [];
        var dist = [];
        var lastPathIndex = apiData.svg_paths.length - 1;
        apiData.svg_paths.forEach(function (pathStr, recordIndex) {
            if (recordIndex === 0 || recordIndex === lastPathIndex)
                return;
            var pathStrParsed = pathStr.split('M').join(',').split(',');
            xVals[recordIndex] = (Number(pathStrParsed[1]) + Number(pathStrParsed[3])) / 2;
            yVals[recordIndex] = (Number(pathStrParsed[2]) + Number(pathStrParsed[4])) / 2;
            if (recordIndex > 1) {
                var xDiff = xVals[recordIndex] - xVals[recordIndex - 1];
                var yDiff = yVals[recordIndex] - yVals[recordIndex - 1];
                dist[recordIndex] = Math.pow((Math.pow(yDiff, 2) + Math.pow(xDiff, 2)), 0.5);
            }
        });
        var sortedDist = dist.sort(function (a, b) { return a - b; });
        return 0.9 * sortedDist[Math.floor(sortedDist.length * 0.05)];
    };
