        if (startIndex < 1)
            startIndex = 1;
        if (interval < 1)
            interval = 1;
        if (startIndex > sequenceLength)
            startIndex = sequenceLength;
        var svg = document.querySelector("svg.rnaTopoSvg");
        if (!svg)
            return;
        // Remove existing annotations
        var existingAnnotations = svg.querySelectorAll('.nucleotide-annotation');
        existingAnnotations.forEach(function (el) { return el.remove(); });
        // Get all nucleotides
        var nucleotides = Array.from(svg.querySelectorAll(".rnaviewEle_".concat(this.pluginOptions.pdbId)));
